class Solution:
    def thousandSeparator(self, n: int) -> str:
        digits = str(n)
        out = []
        count = 0
        for ch in reversed(digits):
            if count == 3:
                out.append('.')
                count = 0
            out.append(ch)
            count += 1
        return ''.join(reversed(out))

