class Solution:
    def thousandSeparator(self, n: int) -> str:
        s = str(n)
        groups = []
        while len(s) > 3:
            groups.append(s[-3:])
            s = s[:-3]
        groups.append(s)
        groups.reverse()
        return '.'.join(groups)

