var thousandSeparator = function(n) {
    let s = String(n);
    const groups = [];
    while (s.length > 3) {
        groups.unshift(s.slice(-3));
        s = s.slice(0, -3);
    }
    groups.unshift(s);
    return groups.join('.');
};
